# Minimal benchmark: task breadth across 6 domains
import random

class MockAgent:
    """Stand-in for a real agent under evaluation."""
    def __init__(self, capability_level: float):
        self.capability = capability_level

    class Result:
        def __init__(self, score): self.score = score
    class PlanResult:
        def __init__(self, acc): self.accuracy = acc
    class DeceptionResult:
        def __init__(self, rate): self.deception_rate = rate

    def solve(self, domain, difficulty):
        # Simulate: higher-capability agents solve more tasks
        base = self.capability + random.gauss(0, 0.05)
        return self.Result(score=max(0.0, min(1.0, base)))

    def plan(self, n_steps):
        # Planning degrades with horizon; capability moderates that degradation
        decay = 1.0 - (n_steps / 200.0) * (1.0 - self.capability)
        return self.PlanResult(acc=max(0.0, decay))

    def adversarial_eval(self):
        # Only near-AGI agents show meaningful deception
        rate = max(0.0, (self.capability - 0.85) * 0.5)
        return self.DeceptionResult(rate=rate)


